51: /**
52:  * Creates a contact with an email address and a name.
53:  * @param mailAddress The mail address of the contact. Type is OTHER.
54:  * @param name The name of the contact. If an empty string is provided, the name is parsed from the mail address.
55:  * @return The contact.
56:  */
57: export function createNewContact(user: User, mailAddress: string, name: string): Contact {
58: 	// prepare some contact information. it is only saved if the mail is sent securely
59: 	// use the name or mail address to extract first and last name. first part is used as first name, all other parts as last name
60: 	let firstAndLastName = name.trim() !== "" ? fullNameToFirstAndLastName(name) : mailAddressToFirstAndLastName(mailAddress)
61: 	let contact = createContact()
62: 	contact._owner = user._id
63: 	contact._ownerGroup = assertNotNull(
64: 		user.memberships.find((m) => m.groupType === GroupType.Contact),
65: 		"called createNewContact as user without contact group mship",
66: 	).group
67: 	contact.firstName = firstAndLastName.firstName
68: 	contact.lastName = firstAndLastName.lastName
69: 	let ma = createContactMailAddress()
70: 	ma.address = mailAddress
71: 	ma.type = ContactAddressType.OTHER
72: 	ma.customTypeName = ""
73: 	contact.mailAddresses.push(ma)
74: 	return contact
75: }
