103: export function getRecipientHeading(mail: Mail, preferNameOnly: boolean) {
104: 	if (isLegacyMail(mail)) {
105: 		const allRecipients = mail.toRecipients.concat(mail.ccRecipients).concat(mail.bccRecipients)
106: 
107: 		if (allRecipients.length > 0) {
108: 			return getMailAddressDisplayText(allRecipients[0].name, allRecipients[0].address, preferNameOnly) + (allRecipients.length > 1 ? ", ..." : "")
109: 		} else {
110: 			return ""
