112: 	} else {
113: 		let recipientCount = parseInt(mail.recipientCount)
114: 		if (recipientCount > 0) {
115: 			let recipient = neverNull(mail.firstRecipient)
116: 			return getMailAddressDisplayText(recipient.name, recipient.address, preferNameOnly) + (recipientCount > 1 ? ", ..." : "")
