327: type AttachmentSizeCheckResult = {
328: 	attachableFiles: Array<Attachment>
329: 	tooBigFiles: Array<string>
330: }
331: 
332: /**
333:  * @param files the files that shall be attached.
334:  * @param maxAttachmentSize the maximum size the new files may have in total to be attached successfully.
335:  */
336: export function checkAttachmentSize(files: ReadonlyArray<Attachment>, maxAttachmentSize: number = MAX_ATTACHMENT_SIZE): AttachmentSizeCheckResult {
337: 	let totalSize = 0
338: 	const attachableFiles: Array<Attachment> = []
339: 	const tooBigFiles: Array<string> = []
340: 	files.forEach((file) => {
341: 		if (totalSize + Number(file.size) > maxAttachmentSize) {
342: 			tooBigFiles.push(file.name)
343: 		} else {
344: 			totalSize += Number(file.size)
345: 			attachableFiles.push(file)
346: 		}
347: 	})
348: 	return {
349: 		attachableFiles,
350: 		tooBigFiles,
351: 	}
352: }
