370: export async function getMoveTargetFolderSystems(model: MailModel, mails: readonly Mail[]): Promise<Array<FolderInfo>> {
371: 	const firstMail = first(mails)
372: 	if (firstMail == null) return []
373: 
374: 	const mailboxDetails = await model.getMailboxDetailsForMail(firstMail)
375: 	if (mailboxDetails == null) {
376: 		return []
377: 	}
378: 	const folderSystem = mailboxDetails.folders
379: 	return folderSystem.getIndentedList().filter((f) => f.folder.mails !== getListId(firstMail))
380: }
