397: export async function loadMailDetails(entityClient: EntityClient, mail: Mail): Promise<MailWrapper> {
398: 	if (isLegacyMail(mail)) {
399: 		return entityClient.load(MailBodyTypeRef, neverNull(mail.body)).then((b) => MailWrapper.body(mail, b))
400: 	} else if (isDetailsDraft(mail)) {
401: 		return entityClient
402: 			.load(MailDetailsDraftTypeRef, neverNull(mail.mailDetailsDraft), undefined, undefined, undefined, mail._ownerEncSessionKey)
403: 			.then((d) => MailWrapper.details(mail, d.details))
404: 	} else {
405: 		const mailDetailsId = neverNull(mail.mailDetails)
406: 
407: 		const providedOwnerEncSessionKeys = new Map<Id, Uint8Array>()
408: 		providedOwnerEncSessionKeys.set(elementIdPart(mailDetailsId), assertNotNull(mail._ownerEncSessionKey))
409: 		return entityClient
410: 			.loadMultiple(MailDetailsBlobTypeRef, listIdPart(mailDetailsId), [elementIdPart(mailDetailsId)], providedOwnerEncSessionKeys)
411: 			.then((d) => MailWrapper.details(mail, d[0].details))
412: 	}
413: }
