/**
 * Regression test for non-legacy mail content decryption failure
 *
 * This test verifies the bug where non-legacy mails fail to decrypt because
 * session keys are not properly propagated when loading related entities
 * (MailDetailsBlob, MailDetailsDraft) through the mail indexer.
 *
 * The issue manifests as "Missing decryption key" errors when opening mails
 * with the new (non-legacy) permission model.
 */

import o from "@tutao/otest"
import {
	aes128RandomKey,
	bitArrayToUint8Array,
	Uint8ArrayToBase64,
	uint8ArrayToBase64,
	downcast,
	neverNull,
	ofClass,
} from "@tutao/tutanota-utils"
import type { Mail, MailDetailsBlob, MailDetails } from "../src/api/entities/tutanota/TypeRefs.js"
import {
	createMail,
	createMailDetailsBlob,
	createMailDetails,
	MailDetailsBlobTypeRef,
	MailTypeRef,
} from "../src/api/entities/tutanota/TypeRefs.js"
import { MailIndexer } from "../src/api/worker/search/MailIndexer.js"
import { SessionKeyNotFoundError } from "../src/api/common/error/SessionKeyNotFoundError.js"
import type { EntityClient } from "../src/api/common/EntityClient.js"
import { object, when, verify, matchers, instance } from "testdouble"
import { DefaultEntityRestCache } from "../src/api/worker/rest/DefaultEntityRestCache.js"
import type { CryptoFacade } from "../src/api/worker/crypto/CryptoFacade.js"
import { MailState } from "../src/api/common/TutanotaConstants.js"

const { anything } = matchers

o.spec("Mail decryption - regression test for non-legacy mails", function () {
	let mailIndexer: MailIndexer
	let entityClientMock: EntityClient
	let entityCacheMock: DefaultEntityRestCache
	let cryptoFacadeMock: CryptoFacade

	o.beforeEach(function () {
		// Create mocks
		entityClientMock = object<EntityClient>()
		entityCacheMock = object<DefaultEntityRestCache>()
		cryptoFacadeMock = object<CryptoFacade>()

		// Create a minimal MailIndexer instance with mocked dependencies
		mailIndexer = new MailIndexer(
			entityClientMock as any,
			entityCacheMock as any,
			cryptoFacadeMock as any,
			null,
			null,
			null,
			null,
		)
	})

	o(
		"Non-legacy mail with MailDetailsBlob fails to decrypt due to missing session key propagation",
		async function () {
			// Setup: Create a non-legacy mail (new permission model) with owner-encrypted session key
			const ownerEncSessionKey = aes128RandomKey()
			const ownerEncSessionKeyBase64 = uint8ArrayToBase64(bitArrayToUint8Array(ownerEncSessionKey))

			const mail = createMail({
				_id: ["listId", "mailId"],
				state: MailState.RECEIVED,
				mailDetails: ["detailsListId", "detailsBlobId"],
				_ownerEncSessionKey: ownerEncSessionKeyBase64,
				_ownerGroup: "ownerGroupId",
			})

			// The mail is NOT a legacy mail (no body field)
			// and NOT a draft (no mailDetailsDraft field)

			// Create the MailDetailsBlob that contains the actual mail content
			const mailDetailsBlob = createMailDetailsBlob({
				_id: ["detailsListId", "detailsBlobId"],
				_ownerEncSessionKey: undefined, // This SHOULD be set by loadMultiple
				_ownerGroup: "ownerGroupId",
				details: createMailDetails({
					body: "This is the decrypted mail body",
					headers: "From: sender@example.com",
				}),
			})

			// Setup: When entityClient tries to load the MailDetailsBlob,
			// it won't receive the session key because loadInChunks doesn't
			// pass providedOwnerEncSessionKeys
			// This causes the resolver to fail with SessionKeyNotFoundError
			when(entityCacheMock.loadMultiple(MailDetailsBlobTypeRef, "detailsListId", ["detailsBlobId"], anything())).thenDo(
				(_typeRef, _listId, _ids, providedKeys) => {
					// BUG DEMONSTRATION: providedKeys is undefined or empty here!
					// This is because loadInChunks in MailIndexer.loadMailDetails
					// does NOT pass the session keys from the parent mail
					if (!providedKeys || providedKeys.size === 0) {
						// When no provided keys are available, the resolver tries to look
						// up the key from the instance's _ownerEncSessionKey field.
						// Since the loaded entity doesn't have it set, decryption fails.
						return Promise.reject(
							new SessionKeyNotFoundError(
								"Could not resolve session key for MailDetailsBlob - " +
									"session key not propagated from parent mail",
							),
						)
					}
					// This code path would be reached if the bug were fixed:
					mailDetailsBlob._ownerEncSessionKey = providedKeys.get("detailsBlobId")
					return Promise.resolve([mailDetailsBlob])
				},
			)

			// Setup: Crypto facade will fail to resolve session key for loaded blob
			// because it doesn't have _ownerEncSessionKey set
			when(cryptoFacadeMock.resolveSessionKey(anything(), anything())).thenReject(
				new SessionKeyNotFoundError(
					"_ownerEncSessionKey is missing on MailDetailsBlob instance - " +
						"indicates session key was not propagated during load",
				),
			)

			// Act: Try to load mail details (which is what happens during indexing)
			// This should fail with SessionKeyNotFoundError due to the bug
			const loadMailDetailsPromise = mailIndexer.loadMailDetails([mail])

			// Assert: The operation fails because the session key was not propagated
			await o.expectsPromise(loadMailDetailsPromise).rejects((error: Error) => {
				// The error message should indicate missing or non-propagated session key
				const message = error.message.toLowerCase()
				const isMissingKeyError =
					message.includes("session key") &&
					(message.includes("not found") ||
						message.includes("not propagated") ||
						message.includes("missing") ||
						message.includes("undefined"))

				return isMissingKeyError && error instanceof SessionKeyNotFoundError
			})
		},
	)

	o(
		"Non-legacy mail with MailDetailsDraft fails to decrypt due to missing session key propagation",
		async function () {
			// Similar test for MailDetailsDraft (draft emails)
			const ownerEncSessionKey = aes128RandomKey()
			const ownerEncSessionKeyBase64 = uint8ArrayToBase64(bitArrayToUint8Array(ownerEncSessionKey))

			const mail = createMail({
				_id: ["listId", "draftMailId"],
				state: MailState.DRAFT,
				mailDetailsDraft: ["draftDetailsListId", "draftDetailsId"],
				_ownerEncSessionKey: ownerEncSessionKeyBase64,
				_ownerGroup: "ownerGroupId",
			})

			// Setup: When trying to load the MailDetailsDraft,
			// the session key is not passed through loadInChunks
			when(entityCacheMock.loadMultiple(anything(), "draftDetailsListId", ["draftDetailsId"], anything())).thenDo(
				(_typeRef, _listId, _ids, providedKeys) => {
					// BUG: providedKeys is empty/undefined
					if (!providedKeys || providedKeys.size === 0) {
						return Promise.reject(
							new SessionKeyNotFoundError(
								"Could not resolve session key for MailDetailsDraft - " +
									"session key not propagated from parent draft mail",
							),
						)
					}
					return Promise.resolve([])
				},
			)

			when(cryptoFacadeMock.resolveSessionKey(anything(), anything())).thenReject(
				new SessionKeyNotFoundError("MailDetailsDraft session key not propagated"),
			)

			// Act: Try to load draft mail details
			const loadMailDetailsPromise = mailIndexer.loadMailDetails([mail])

			// Assert: Fails with session key error
			await o.expectsPromise(loadMailDetailsPromise).rejects((error: Error) => {
				return error instanceof SessionKeyNotFoundError && error.message.includes("session key")
			})
		},
	)

	o(
		"Batch loading multiple non-legacy mails without session key propagation fails to decrypt",
		async function () {
			// Test batch loading scenario where multiple mails are indexed at once
			const ownerEncSessionKey1 = aes128RandomKey()
			const ownerEncSessionKey2 = aes128RandomKey()

			const mail1 = createMail({
				_id: ["listId", "mailId1"],
				state: MailState.RECEIVED,
				mailDetails: ["detailsListId", "blobId1"],
				_ownerEncSessionKey: uint8ArrayToBase64(bitArrayToUint8Array(ownerEncSessionKey1)),
				_ownerGroup: "ownerGroupId",
			})

			const mail2 = createMail({
				_id: ["listId", "mailId2"],
				state: MailState.RECEIVED,
				mailDetails: ["detailsListId", "blobId2"],
				_ownerEncSessionKey: uint8ArrayToBase64(bitArrayToUint8Array(ownerEncSessionKey2)),
				_ownerGroup: "ownerGroupId",
			})

			// Setup: When loading multiple blobs without per-entity session keys
			when(
				entityCacheMock.loadMultiple(
					MailDetailsBlobTypeRef,
					"detailsListId",
					["blobId1", "blobId2"],
					anything(),
				),
			).thenDo((_typeRef, _listId, _ids, providedKeys) => {
				// BUG: In batch loading, the per-entity session keys are not propagated
				// Both blobs are loaded without their respective session keys
				if (!providedKeys || providedKeys.size < 2) {
					// Should have 2 session keys (one for each blob), but doesn't
					return Promise.reject(
						new SessionKeyNotFoundError(
							`Expected 2 session keys for batch load, got ${providedKeys?.size || 0}`,
						),
					)
				}
				return Promise.resolve([])
			})

			when(cryptoFacadeMock.resolveSessionKey(anything(), anything())).thenReject(
				new SessionKeyNotFoundError("Batch load missing per-entity session keys"),
			)

			// Act: Try to load multiple mails
			const loadMailDetailsPromise = mailIndexer.loadMailDetails([mail1, mail2])

			// Assert: Batch loading fails due to missing per-entity session keys
			await o.expectsPromise(loadMailDetailsPromise).rejects((error: Error) => {
				return error instanceof SessionKeyNotFoundError
			})
		},
	)
})

