				(_typeRef, _listId, _ids, providedKeys) => {
					// BUG DEMONSTRATION: providedKeys is undefined or empty here!
					// This is because loadInChunks in MailIndexer.loadMailDetails
					// does NOT pass the session keys from the parent mail
					if (!providedKeys || providedKeys.size === 0) {
						// When no provided keys are available, the resolver tries to look
						// up the key from the instance's _ownerEncSessionKey field.
						// Since the loaded entity doesn't have it set, decryption fails.
						return Promise.reject(
							new SessionKeyNotFoundError(
								"Could not resolve session key for MailDetailsBlob - " +
									"session key not propagated from parent mail",
							),
						)
					}
					// This code path would be reached if the bug were fixed:
					mailDetailsBlob._ownerEncSessionKey = providedKeys.get("detailsBlobId")
					return Promise.resolve([mailDetailsBlob])
				},
			)

			// Setup: Crypto facade will fail to resolve session key for loaded blob
			// because it doesn't have _ownerEncSessionKey set
			when(cryptoFacadeMock.resolveSessionKey(anything(), anything())).thenReject(
				new SessionKeyNotFoundError(
					"_ownerEncSessionKey is missing on MailDetailsBlob instance - " +
						"indicates session key was not propagated during load",
				),
			)

			// Act: Try to load mail details (which is what happens during indexing)
			// This should fail with SessionKeyNotFoundError due to the bug
			const loadMailDetailsPromise = mailIndexer.loadMailDetails([mail])

			// Assert: The operation fails because the session key was not propagated
			await o.expectsPromise(loadMailDetailsPromise).rejects((error: Error) => {
				// The error message should indicate missing or non-propagated session key
				const message = error.message.toLowerCase()
				const isMissingKeyError =
					message.includes("session key") &&
					(message.includes("not found") ||
						message.includes("not propagated") ||
						message.includes("missing") ||
						message.includes("undefined"))

				return isMissingKeyError && error instanceof SessionKeyNotFoundError
			})
		},
	)

	o(
		"Non-legacy mail with MailDetailsDraft fails to decrypt due to missing session key propagation",
		async function () {
			// Similar test for MailDetailsDraft (draft emails)
			const ownerEncSessionKey = aes128RandomKey()
			const ownerEncSessionKeyBase64 = uint8ArrayToBase64(bitArrayToUint8Array(ownerEncSessionKey))

			const mail = createMail({
				_id: ["listId", "draftMailId"],
				state: MailState.DRAFT,
				mailDetailsDraft: ["draftDetailsListId", "draftDetailsId"],
				_ownerEncSessionKey: ownerEncSessionKeyBase64,
				_ownerGroup: "ownerGroupId",
			})

			// Setup: When trying to load the MailDetailsDraft,
			// the session key is not passed through loadInChunks
			when(entityCacheMock.loadMultiple(anything(), "draftDetailsListId", ["draftDetailsId"], anything())).thenDo(
				(_typeRef, _listId, _ids, providedKeys) => {
					// BUG: providedKeys is empty/undefined
					if (!providedKeys || providedKeys.size === 0) {
						return Promise.reject(
							new SessionKeyNotFoundError(
								"Could not resolve session key for MailDetailsDraft - " +
									"session key not propagated from parent draft mail",
