				// Both blobs are loaded without their respective session keys
				if (!providedKeys || providedKeys.size < 2) {
					// Should have 2 session keys (one for each blob), but doesn't
					return Promise.reject(
						new SessionKeyNotFoundError(
							`Expected 2 session keys for batch load, got ${providedKeys?.size || 0}`,
						),
					)
				}
				return Promise.resolve([])
			})

