				state: MailState.DRAFT,
				mailDetailsDraft: ["draftDetailsListId", "draftDetailsId"],
				_ownerEncSessionKey: ownerEncSessionKeyBase64,
				_ownerGroup: "ownerGroupId",
			})

			// Setup: When trying to load the MailDetailsDraft,
			// the session key is not passed through loadInChunks
			when(entityCacheMock.loadMultiple(anything(), "draftDetailsListId", ["draftDetailsId"], anything())).thenDo(
				(_typeRef, _listId, _ids, providedKeys) => {
					// BUG: providedKeys is empty/undefined
					if (!providedKeys || providedKeys.size === 0) {
						return Promise.reject(
							new SessionKeyNotFoundError(
								"Could not resolve session key for MailDetailsDraft - " +
									"session key not propagated from parent draft mail",
							),
						)
					}
					return Promise.resolve([])
				},
			)

			when(cryptoFacadeMock.resolveSessionKey(anything(), anything())).thenReject(
				new SessionKeyNotFoundError("MailDetailsDraft session key not propagated"),
			)

			// Act: Try to load draft mail details
			const loadMailDetailsPromise = mailIndexer.loadMailDetails([mail])

			// Assert: Fails with session key error
			await o.expectsPromise(loadMailDetailsPromise).rejects((error: Error) => {
				return error instanceof SessionKeyNotFoundError && error.message.includes("session key")
			})
		},
	)

	o(
		"Batch loading multiple non-legacy mails without session key propagation fails to decrypt",
		async function () {
			// Test batch loading scenario where multiple mails are indexed at once
			const ownerEncSessionKey1 = aes128RandomKey()
			const ownerEncSessionKey2 = aes128RandomKey()

			const mail1 = createMail({
				_id: ["listId", "mailId1"],
				state: MailState.RECEIVED,
				mailDetails: ["detailsListId", "blobId1"],
				_ownerEncSessionKey: uint8ArrayToBase64(bitArrayToUint8Array(ownerEncSessionKey1)),
				_ownerGroup: "ownerGroupId",
			})

			const mail2 = createMail({
				_id: ["listId", "mailId2"],
				state: MailState.RECEIVED,
				mailDetails: ["detailsListId", "blobId2"],
				_ownerEncSessionKey: uint8ArrayToBase64(bitArrayToUint8Array(ownerEncSessionKey2)),
				_ownerGroup: "ownerGroupId",
			})

			// Setup: When loading multiple blobs without per-entity session keys
			when(
				entityCacheMock.loadMultiple(
					MailDetailsBlobTypeRef,
					"detailsListId",
					["blobId1", "blobId2"],
					anything(),
				),
			).thenDo((_typeRef, _listId, _ids, providedKeys) => {
				// BUG: In batch loading, the per-entity session keys are not propagated
				// Both blobs are loaded without their respective session keys
				if (!providedKeys || providedKeys.size < 2) {
					// Should have 2 session keys (one for each blob), but doesn't
					return Promise.reject(
						new SessionKeyNotFoundError(
							`Expected 2 session keys for batch load, got ${providedKeys?.size || 0}`,
						),
					)
				}
				return Promise.resolve([])
			})

			when(cryptoFacadeMock.resolveSessionKey(anything(), anything())).thenReject(
				new SessionKeyNotFoundError("Batch load missing per-entity session keys"),
			)

			// Act: Try to load multiple mails
			const loadMailDetailsPromise = mailIndexer.loadMailDetails([mail1, mail2])

			// Assert: Batch loading fails due to missing per-entity session keys
			await o.expectsPromise(loadMailDetailsPromise).rejects((error: Error) => {
				return error instanceof SessionKeyNotFoundError
			})
		},
	)
})

