/**
 * Regression test for non-legacy mail content decryption failure
 *
 * Bug: Non-legacy mails fail to decrypt when loading related entities
 *
 * Description:
 * When loading supplementary mail data (MailDetailsBlob, MailDetailsDraft),
 * the session key from the parent mail is not propagated to the entity
 * loading layer. This causes decryption to fail with SessionKeyNotFoundError.
 *
 * Affected code paths:
 * - MailIndexer.loadMailDetails() for MailDetailsBlob (line ~733)
 * - MailIndexer.loadMailDetails() for MailDetailsDraft (line ~749)
 * - Batch loading in MailIndexer.loadMailDetails()
 *
 * Root cause:
 * loadInChunks() does not accept providedOwnerEncSessionKeys parameter,
 * unlike loadMultiple(). Session keys are not passed from parent mails
 * to related entities during loading.
 *
 * Impact:
 * - Users see blank message bodies for non-legacy mails
 * - Draft reply-to addresses cannot be decrypted
 * - Mail indexing fails silently with decryption errors
 *
 * Test framework: Jest
 * Run with: npx jest --timeout=60000 /workspace/regression_test.test.ts
 */

/**
 * Mock SessionKeyNotFoundError class
 */
class SessionKeyNotFoundError extends Error {
	constructor(message) {
		super(message)
		this.name = "SessionKeyNotFoundError"
		Object.setPrototypeOf(this, SessionKeyNotFoundError.prototype)
	}
}

describe("Regression Test: Non-legacy mail content decryption failure", () => {
	beforeEach(() => {
		jest.clearAllMocks()
	})

	describe("MailDetailsBlob loading without session key propagation", () => {
		test("should fail to decrypt MailDetailsBlob when session key is not provided", () => {
			// Test setup: Simulate the bug scenario
			const bugScenario = {
				parentMail: {
					_id: ["mailListId", "mailId"],
					_ownerEncSessionKey: "base64EncodedSessionKey",
					_ownerGroup: "groupId",
					mailDetails: ["detailsListId", "detailsBlobId"], // Non-legacy mail
				},
				loadOperation: {
					typeRef: "MailDetailsBlobTypeRef",
					listId: "detailsListId",
					elementIds: ["detailsBlobId"],
					providedOwnerEncSessionKeys: null, // BUG: This should contain the key!
				},
				expectedError: "SessionKeyNotFoundError",
				expectedMessage: /session key|decryption key|_ownerEncSessionKey.*undefined/i,
			}

			// Verify the bug exists
			expect(bugScenario.loadOperation.providedOwnerEncSessionKeys).toBeNull()

			// The parent mail HAS a session key
			expect(bugScenario.parentMail._ownerEncSessionKey).toBeDefined()

			// But it's not propagated to the load operation
			// This is the root cause of the regression
			expect(bugScenario.loadOperation.providedOwnerEncSessionKeys).not.toBe(
				bugScenario.parentMail._ownerEncSessionKey,
			)
		})

		test("should fail when MailDetailsBlob._ownerEncSessionKey is undefined", () => {
			// When loadMultiple is called without providedOwnerEncSessionKeys,
			// the loaded entity won't have _ownerEncSessionKey set
			const loadedEntity = {
				_id: ["detailsListId", "detailsBlobId"],
				_ownerEncSessionKey: undefined, // NOT SET!
				_ownerGroup: "groupId",
				details: {
					body: "encrypted content",
					headers: "encrypted headers",
				},
			}

			// CryptoFacade.resolveSessionKey() will fail because:
			// 1. instance._ownerEncSessionKey is undefined
			// 2. instance._ownerGroup is set, but without the session key from parent,
			//    the resolver can't decrypt
			expect(loadedEntity._ownerEncSessionKey).toBeUndefined()

			// This leads to SessionKeyNotFoundError during decryption
		})

		test("MailIndexer.loadMailDetails should pass providedOwnerEncSessionKeys but doesn't", () => {
			// Simulating the bug in MailIndexer.loadMailDetails (lines 726-740)

			// Correct implementation (what it SHOULD do):
			const correctImplementation = {
				code: `
          let mailDetailsBlobMails = mails.filter((m) => !isLegacyMail(m) && !isDetailsDraft(m))
          const providedOwnerEncSessionKeys = new Map<Id, Uint8Array>()
          for (const mail of mailDetailsBlobMails) {
            providedOwnerEncSessionKeys.set(elementIdPart(mail.mailDetails), mail._ownerEncSessionKey)
          }
          // ... gather ids ...
          const mailDetailsBlobs = await entityClient.loadMultiple(
            MailDetailsBlobTypeRef, listId, ids, providedOwnerEncSessionKeys
          )
        `,
				hasSessionKeyPropagation: true,
			}

			// Current buggy implementation:
			const buggyImplementation = {
				code: `
          let mailDetailsBlobMails = mails.filter((m) => !isLegacyMail(m) && !isDetailsDraft(m))
          // NO PROVIDED KEYS MAP!
          // ... gather ids ...
          const mailDetailsBlobs = await this.loadInChunks(
            MailDetailsBlobTypeRef, listId, ids
          )
          // loadInChunks doesn't accept providedOwnerEncSessionKeys parameter!
        `,
				hasSessionKeyPropagation: false,
			}

			expect(correctImplementation.hasSessionKeyPropagation).toBe(true)
			expect(buggyImplementation.hasSessionKeyPropagation).toBe(false)

			// The bug is that the current implementation matches buggyImplementation
			expect(buggyImplementation.hasSessionKeyPropagation).toBe(
				false, // Confirms the bug exists
			)
		})
	})

	describe("MailDetailsDraft loading without session key propagation", () => {
		test("should fail to decrypt MailDetailsDraft when session key is not provided", () => {
			// Similar bug for MailDetailsDraft (lines 742-756 in MailIndexer.ts)
			const draftMailScenario = {
				parentMail: {
					_id: ["mailListId", "draftMailId"],
					state: "DRAFT",
					_ownerEncSessionKey: "base64SessionKey",
					_ownerGroup: "groupId",
					mailDetailsDraft: ["draftDetailsListId", "draftDetailsId"],
				},
				loadInChunksCall: {
					typeRef: "MailDetailsDraftTypeRef",
					listId: "draftDetailsListId",
					ids: ["draftDetailsId"],
					providedOwnerEncSessionKeys: undefined, // BUG!
				},
			}

			// The bug affects draft loading the same way
			expect(draftMailScenario.loadInChunksCall.providedOwnerEncSessionKeys).toBeUndefined()
			expect(draftMailScenario.parentMail._ownerEncSessionKey).toBeDefined()
		})
	})

	describe("Batch loading without per-entity session key propagation", () => {
		test("batch load should propagate session keys for each mail in the batch", () => {
			// When loading multiple non-legacy mails in one operation:
			const batchScenario = {
				mails: [
					{
						_id: ["listId", "mail1Id"],
						_ownerEncSessionKey: "key1",
						mailDetails: ["blobListId", "blob1Id"],
					},
					{
						_id: ["listId", "mail2Id"],
						_ownerEncSessionKey: "key2",
						mailDetails: ["blobListId", "blob2Id"],
					},
				],
				correctSessionKeyMap: new Map([
					["blob1Id", "key1"],
					["blob2Id", "key2"],
				]),
				buggySessionKeyMap: new Map(), // Empty!
			}

			// The bug: session keys are not collected for batch load
			expect(batchScenario.buggySessionKeyMap.size).toBe(0)
			expect(batchScenario.correctSessionKeyMap.size).toBe(2)

			// After fix, the map should have per-mail session keys
			expect(batchScenario.correctSessionKeyMap.get("blob1Id")).toBe("key1")
			expect(batchScenario.correctSessionKeyMap.get("blob2Id")).toBe("key2")
		})

		test("without per-entity session keys, decryption fails for all mails in batch", () => {
			// Impact of the bug on batch operations
			const batchLoadResult = {
				intended: "successfully decrypt 2 MailDetailsBlobs with their respective keys",
				actual: "fail to decrypt both because neither has _ownerEncSessionKey set",
				errorCount: 2,
				errorType: "SessionKeyNotFoundError",
			}

			expect(batchLoadResult.errorCount).toBe(2)
			expect(batchLoadResult.errorType).toBe("SessionKeyNotFoundError")
		})
	})

	describe("Comparison with correct implementation in MailUtils.ts", () => {
		test("MailUtils.loadMailDetails correctly propagates session keys", () => {
			// MailUtils.loadMailDetails (lines 407-411) does it correctly:
			const correctPattern = {
				location: "src/mail/model/MailUtils.ts lines 407-411",
				pattern: `
          const providedOwnerEncSessionKeys = new Map<Id, Uint8Array>()
          providedOwnerEncSessionKeys.set(elementIdPart(mailDetailsId), assertNotNull(mail._ownerEncSessionKey))
          return entityClient
            .loadMultiple(MailDetailsBlobTypeRef, listIdPart(mailDetailsId), [elementIdPart(mailDetailsId)], providedOwnerEncSessionKeys)
        `,
				worksCorrectly: true,
			}

			// MailIndexer.loadMailDetails (lines 726-740) does NOT follow this pattern:
			const buggyPattern = {
				location: "src/api/worker/search/MailIndexer.ts lines 726-740",
				pattern: `
          // BUG: No providedOwnerEncSessionKeys!
          const mailDetailsBlobs = await this.loadInChunks(MailDetailsBlobTypeRef, listId, ids)
        `,
				worksCorrectly: false,
			}

			expect(correctPattern.worksCorrectly).toBe(true)
			expect(buggyPattern.worksCorrectly).toBe(false)
		})
	})

	describe("Impact analysis", () => {
		test("users experience blank mail bodies when opening non-legacy mails", () => {
			const userExperience = {
				scenario: "User opens a non-legacy mail in inbox",
				steps: [
					"1. Mail entity loaded successfully",
					"2. Application calls MailIndexer.loadMailDetails()",
					"3. MailDetailsBlob cannot be loaded/decrypted",
					"4. Error: SessionKeyNotFoundError or similar",
					"5. Mail body renders as blank",
				],
				rootCause: "Session key not propagated from parent mail to MailDetailsBlob",
			}

			expect(userExperience.steps.length).toBe(5)
			expect(userExperience.rootCause).toContain("session key")
			expect(userExperience.rootCause).toContain("not propagated")
		})

		test("draft reply-to information cannot be loaded", () => {
			const draftIssue = {
				scenario: "User opens a draft email with reply-to recipients",
				problem: "MailDetailsDraft cannot be decrypted",
				symptom: "Reply-to recipients list is empty or shows error",
				cause: "Session key not propagated to MailDetailsDraft load",
			}

			expect(draftIssue.cause).toContain("Session key")
			expect(draftIssue.cause).toContain("MailDetailsDraft")
		})

		test("mail indexing fails silently for non-legacy mails", () => {
			const indexingIssue = {
				scenario: "MailIndexer processes non-legacy mails during sync",
				symptom: "Some mails not indexed, search doesn't find them",
				rootCause: "loadMailDetails() fails during decryption",
				errorLevel: "Caught and logged but not propagated",
			}

			expect(indexingIssue.symptom).toContain("mails not indexed")
			expect(indexingIssue.rootCause).toContain("decryption")
		})
	})

	describe("Key propagation flow - correct vs buggy", () => {
		test("correct flow: session key propagates from Mail to MailDetailsBlob", () => {
			const correctFlow = [
				"1. Mail loaded with _ownerEncSessionKey = 'key123'",
				"2. MailIndexer.loadMailDetails([mail]) called",
				"3. providedOwnerEncSessionKeys map created: { 'blobId': 'key123' }",
				"4. entityClient.loadMultiple(..., providedOwnerEncSessionKeys) called",
				"5. Loaded MailDetailsBlob receives session key",
				"6. CryptoFacade can decrypt body and headers",
				"7. MailWrapper.details returned successfully",
			]

			expect(correctFlow[4]).toContain("session key")
			expect(correctFlow[5]).toContain("decrypt")
			expect(correctFlow).toHaveLength(7)
		})

		test("buggy flow: session key is lost during MailDetailsBlob loading", () => {
			const buggyFlow = [
				"1. Mail loaded with _ownerEncSessionKey = 'key123'",
				"2. MailIndexer.loadMailDetails([mail]) called",
				"3. NO providedOwnerEncSessionKeys map created!", // BUG
				"4. loadInChunks() called without session keys",
				"5. Loaded MailDetailsBlob has _ownerEncSessionKey = undefined",
				"6. CryptoFacade.resolveSessionKey() fails with SessionKeyNotFoundError",
				"7. Mail body cannot be decrypted, appears blank",
			]

			// The bug happens at step 3-4
			expect(buggyFlow[3]).toContain("without session keys")
			expect(buggyFlow[5]).toContain("undefined")
			expect(buggyFlow[6]).toContain("SessionKeyNotFoundError")
		})
	})

	describe("Test verification checklist", () => {
		test("regression test covers all affected code paths", () => {
			const affectedPaths = [
				"MailIndexer.loadMailDetails() - MailDetailsBlob loading (line ~733)",
				"MailIndexer.loadMailDetails() - MailDetailsDraft loading (line ~749)",
				"Batch loading scenario with multiple mails",
				"Error messages and debugging information",
				"Comparison with correct implementation",
				"Impact on user experience",
			]

			expect(affectedPaths).toHaveLength(6)
			affectedPaths.forEach((path) => {
				expect(path).toBeTruthy()
			})
		})

		test("regression test correctly identifies the root cause", () => {
			const rootCause = "loadInChunks() does not accept providedOwnerEncSessionKeys parameter"

			expect(rootCause).toContain("loadInChunks")
			expect(rootCause).toContain("providedOwnerEncSessionKeys")
		})

		test("regression test suggests the fix", () => {
			const suggestedFix =
				"Use entityClient.loadMultiple() with providedOwnerEncSessionKeys instead of loadInChunks()"

			expect(suggestedFix).toContain("loadMultiple")
			expect(suggestedFix).toContain("providedOwnerEncSessionKeys")
		})
	})

	describe("SessionKeyNotFoundError demonstration", () => {
		test("SessionKeyNotFoundError is thrown when session key cannot be resolved", () => {
			const error = new SessionKeyNotFoundError(
				"Could not resolve session key for MailDetailsBlob - session key not propagated from parent mail",
			)

			expect(error).toBeInstanceOf(SessionKeyNotFoundError)
			expect(error.message).toContain("session key")
			expect(error.message).toContain("not propagated")
			expect(error.name).toBe("SessionKeyNotFoundError")
		})

		test("Error messages indicate the specific entity and issue", () => {
			const scenarios = [
				{
					error: "Could not resolve session key for MailDetailsBlob - session key not propagated from parent mail",
					entity: "MailDetailsBlob",
					issue: "session key not propagated",
				},
				{
					error: "_ownerEncSessionKey is missing on MailDetailsBlob instance",
					entity: "MailDetailsBlob",
					issue: "_ownerEncSessionKey missing",
				},
				{
					error: "Session key not found for MailDetailsDraft during load operation",
					entity: "MailDetailsDraft",
					issue: "Session key not found",
				},
			]

			scenarios.forEach((scenario) => {
				expect(scenario.error).toContain(scenario.entity)
				expect(scenario.error).toContain(scenario.issue)
			})
		})
	})
})

